// ---------------------------------------------------------------------------
// Easing SVG curve approximation (40×8 path visual)
// ---------------------------------------------------------------------------
function easingSVG([x1, y1, x2, y2]) {
  // Sample 20 points along the cubic bezier at t in [0,1]
  function sampleCubic(t) {
    // De Casteljau for cubic bezier (P0=0,0, P1=x1,y1, P2=x2,y2, P3=1,1) — for x axis only to get progress
    // Use parametric sampling directly: x(t), y(t)
    const bx = (1 - t) * (1 - t) * (1 - t) * 0 + 3 * (1 - t) * (1 - t) * t * x1 + 3 * (1 - t) * t * t * x2 + t * t * t * 1;
    const by = (1 - t) * (1 - t) * (1 - t) * 0 + 3 * (1 - t) * (1 - t) * t * y1 + 3 * (1 - t) * t * t * y2 + t * t * t * 1;
    return [bx * 40, (1 - by) * 8];
  }
  const pts = [];
  for (let i = 0; i <= 20; i++) {
    pts.push(sampleCubic(i / 20));
  }
  const d = pts.map(([x, y], i) => `${i === 0 ? 'M' : 'L'}${x.toFixed(1)} ${y.toFixed(1)}`).join(' ');
  return `<svg width="40" height="8" viewBox="0 0 40 8" class="curve-preview" style="overflow:visible">
    <path d="${d}" fill="none" stroke="#0f62fe" stroke-width="1.5"/>
  </svg>`;
}

